```typescript
import { execFileSync } from "node:child_process";

/**
 * Runs `ffprobe` to print format info for the file at mediaPath
 * and returns the command's output as a string.
 */
export function probeMedia(mediaPath: string): string {
  return execFileSync(
    "ffprobe",
    [
      "-v", "error",
      "-show_format",
      "-i", mediaPath,
    ],
    { encoding: "utf8" },
  );
}
```

