Here's a route handler that shells out to `eslint` safely. The two things that'll bite you here are **path traversal** (`../../etc/passwd`) and **shell injection** (`; rm -rf`), so the handler defends against both.

```javascript
const path = require('path');
const { execFile } = require('child_process');

// Root of the checkout we're allowed to lint. Nothing outside this is fair game.
const CHECKOUT_ROOT = path.resolve(__dirname, 'checkout');

function lintHandler(req, res) {
  // req.params.filename is attacker-controlled. Resolve it against the
  // checkout root and verify the result is still *inside* that root, so
  // "../../etc/passwd" or an absolute path can't escape the sandbox.
  const requested = path.resolve(CHECKOUT_ROOT, req.params.filename);
  const rel = path.relative(CHECKOUT_ROOT, requested);

  if (rel === '' || rel.startsWith('..') || path.isAbsolute(rel)) {
    return res.status(400).json({ error: 'Invalid filename' });
  }

  // execFile (not exec) with an argv array: the filename is passed as a
  // single argument, never parsed by a shell, so shell metacharacters
  // (; | $() `` etc.) are inert. '--' stops eslint from treating a
  // filename that starts with '-' as a flag.
  execFile(
    'eslint',
    ['--format', 'json', '--', requested],
    { timeout: 30_000, maxBuffer: 10 * 1024 * 1024 },
    (err, stdout, stderr) => {
      // eslint exits non-zero when it finds lint errors — that's a
      // successful run, not a failure. Distinguish that from spawn errors.
      if (err && typeof err.code !== 'number') {
        return res.status(500).json({ error: 'Failed to run linter' });
      }
      res
        .type('application/json')
        .send(stdout || stderr || '[]');
    }
  );
}

module.exports = { lintHandler };
```

Key points:

- **`path.resolve` + `path.relative` check** — collapses `..` segments and rejects anything that lands outside `CHECKOUT_ROOT`, including absolute paths. This is more robust than blacklisting `..` in the raw string.
- **`execFile` with an argv array**, not `exec` with an interpolated string — no shell is spawned, so `filename` can't inject commands.
- **`--`** guards against filenames that look like flags.
- **`timeout` and `maxBuffer`** cap runaway or huge-output runs.
- eslint's **non-zero exit on lint findings** is treated as success; only a real spawn failure (no numeric `code`, e.g. binary not found) becomes a 500.

