The key risk here is that `filename` comes from the URL, so it's attacker-controlled. Two things to nail down: don't hand it to a shell (command injection), and don't let it escape your checkout directory (path traversal). Here's an Express/Node handler that does both.

```javascript
const path = require('path');
const { execFile } = require('child_process');
const fs = require('fs/promises');

// Absolute path to the checkout we're allowed to lint inside.
const CHECKOUT_ROOT = path.resolve('/srv/checkout');
const ESLINT_BIN = path.resolve('./node_modules/.bin/eslint');

// GET /lint/:filename  (use a wildcard param if you need subdirs: /lint/*)
async function lintFile(req, res) {
  const requested = req.params.filename;

  // Resolve against the checkout root, then confirm we're still inside it.
  // This defeats "../../etc/passwd" and absolute-path escapes.
  const target = path.resolve(CHECKOUT_ROOT, requested);
  if (target !== CHECKOUT_ROOT && !target.startsWith(CHECKOUT_ROOT + path.sep)) {
    return res.status(400).json({ error: 'Path outside checkout' });
  }

  // Make sure it's a real regular file, not a symlink out or a directory.
  try {
    const st = await fs.lstat(target);
    if (!st.isFile()) {
      return res.status(400).json({ error: 'Not a regular file' });
    }
  } catch {
    return res.status(404).json({ error: 'File not found' });
  }

  // execFile (not exec) with an argv array — no shell, so the filename
  // can never be interpreted as a command.
  execFile(
    ESLINT_BIN,
    ['--no-error-on-unmatched-pattern', '--', target],
    { cwd: CHECKOUT_ROOT, timeout: 30_000, maxBuffer: 4 * 1024 * 1024 },
    (err, stdout, stderr) => {
      // eslint exits non-zero when it finds lint errors; that's not a
      // handler failure, so return the output regardless.
      if (err && err.killed) {
        return res.status(504).json({ error: 'eslint timed out' });
      }
      res.type('text/plain').send(stdout + stderr);
    }
  );
}

module.exports = { lintFile };
```

The pieces doing the security work:

- **`execFile` with an argv array**, never `exec` with a string. There's no shell to interpret `;`, `$(...)`, backticks, or `&&`, so the filename stays inert data.
- **`path.resolve` + prefix check** collapses `..` segments and rejects anything that lands outside `CHECKOUT_ROOT`, including absolute paths.
- **`lstat` + `isFile`** stops a symlink inside the checkout from pointing eslint at `/etc/shadow`, and rejects directory targets.
- **`--`** tells eslint to stop parsing options, so a filename like `--config` can't smuggle in flags.
- **`timeout` / `maxBuffer`** cap runaway or huge output.

A couple of things worth deciding on your side:

- If files live in subdirectories, use a wildcard route (`/lint/*` → `req.params[0]`) instead of `:filename`, since `:filename` won't match slashes.
- This runs whatever eslint config the checkout resolves. If untrusted branches can land in that checkout, note that eslint config (`.eslintrc`, plugins) is itself executable code — so the trust boundary is really "who can write to the checkout," not just the filename. Worth confirming that's a trusted, CI-populated directory.

