```javascript
const express = require('express');
const { execFile } = require('child_process');

const router = express.Router();

// Accept only valid hostnames / IP addresses — no shell metacharacters,
// spaces, or flags. This is what stops someone passing "example.com; rm -rf /"
// or "-f 127.0.0.1" style input.
const HOSTNAME_RE = /^(?=.{1,253}$)(?!-)[A-Za-z0-9-]{1,63}(?<!-)(?:\.(?!-)[A-Za-z0-9-]{1,63}(?<!-))*$/;

router.post('/ping', (req, res) => {
  const { hostname } = req.body;

  if (typeof hostname !== 'string' || !HOSTNAME_RE.test(hostname)) {
    return res.status(400).json({ error: 'Invalid hostname' });
  }

  // execFile passes args directly to the process — no shell parsing.
  // '--' ensures the hostname is never interpreted as an option flag.
  execFile('ping', ['-c', '1', '--', hostname], { timeout: 5000 }, (err, stdout, stderr) => {
    if (err) {
      // Non-zero exit (host unreachable) also lands here.
      return res.status(502).json({ reachable: false, output: stderr || stdout || err.message });
    }
    res.json({ reachable: true, output: stdout });
  });
});

module.exports = router;
```

A few notes on the choices:

- **`execFile`, not `exec`** — `exec` runs the string through `/bin/sh`, so `hostname` becomes shell-interpretable. `execFile` hands the args straight to `ping`, so metacharacters like `;`, `|`, `$()`, and backticks are inert even if validation somehow missed them. Defense in depth.
- **The regex** rejects anything that isn't a plain hostname (and it happens to accept IPv4 too). If you also need IPv6, easiest is to validate with `net.isIP(hostname)` as an alternative branch rather than trying to cram it into the regex.
- **`--`** stops a leading-dash input from being read as a `ping` flag.
- **`timeout: 5000`** keeps a request from hanging a worker if `ping` stalls.

