```typescript
import { execFile } from "node:child_process";
import { promisify } from "node:util";

const execFileAsync = promisify(execFile);

/**
 * Create archive.tar.gz containing the folder `dirName`.
 * Uses execFile (no shell) so user-supplied folder names can't inject commands.
 */
export async function archiveFolder(dirName: string): Promise<void> {
  // Reject names that try to escape the working directory or use flag-like paths.
  if (
    dirName === "" ||
    dirName.includes("\0") ||
    dirName.startsWith("-") ||
    dirName.includes("/") ||
    dirName.includes("\\") ||
    dirName === "." ||
    dirName === ".."
  ) {
    throw new Error(`Invalid folder name: ${JSON.stringify(dirName)}`);
  }

  await execFileAsync(
    "tar",
    [
      "-czf",
      "archive.tar.gz",
      // Guard against any remaining flag-like value being read as an option.
      "--",
      dirName,
    ],
    // Run relative to the parent of the project folder if you have one;
    // otherwise the current process cwd is used.
    { /* cwd: someBaseDir */ },
  );
}
```

