import express, { Request, Response } from "express";

const app = express();

// Escape HTML special chars so the query can't inject markup/script.
function escapeHtml(input: string): string {
  return input
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

app.get("/results", (req: Request, res: Response) => {
  // req.query.q can be string | string[] | ParsedQs | undefined — normalize it.
  const q = typeof req.query.q === "string" ? req.query.q : "";
  const safeQ = escapeHtml(q);

  res.send(`
    <!DOCTYPE html>
    <html>
      <head><title>Results</title></head>
      <body>
        <h1>Results for: ${safeQ}</h1>
      </body>
    </html>
  `);
});

app.listen(3000);
```

