```js
const express = require('express');
const path = require('path');
const fs = require('fs/promises');
const { execFile } = require('child_process');

const router = express.Router();

// Root of your checkout — the only tree we'll ever lint.
const CHECKOUT_ROOT = path.resolve(process.env.CHECKOUT_ROOT || '/srv/checkout');

// Full path to the local eslint binary. Pinning this avoids picking up
// some other `eslint` on PATH.
const ESLINT_BIN = path.resolve(
  process.env.ESLINT_BIN || path.join(CHECKOUT_ROOT, 'node_modules/.bin/eslint')
);

// GET /lint?file=src/foo.js
router.get('/lint', async (req, res) => {
  const requested = req.query.file;

  if (typeof requested !== 'string' || requested.length === 0) {
    return res.status(400).json({ error: 'Missing "file" parameter.' });
  }

  // Resolve the requested path *inside* the checkout and confirm it
  // didn't escape. path.resolve collapses `..`, so we compare the
  // result against the root with a trailing separator.
  const target = path.resolve(CHECKOUT_ROOT, requested);
  const rootWithSep = CHECKOUT_ROOT.endsWith(path.sep)
    ? CHECKOUT_ROOT
    : CHECKOUT_ROOT + path.sep;

  if (target !== CHECKOUT_ROOT && !target.startsWith(rootWithSep)) {
    return res.status(400).json({ error: 'Path is outside the checkout.' });
  }

  // Reject anything that isn't a regular file (dirs, symlinks, sockets).
  try {
    const stat = await fs.lstat(target);
    if (!stat.isFile()) {
      return res.status(400).json({ error: 'Not a regular file.' });
    }
  } catch {
    return res.status(404).json({ error: 'File not found.' });
  }

  // execFile (not exec) => args are passed directly, no shell to inject into.
  execFile(
    ESLINT_BIN,
    ['--no-error-on-unmatched-pattern', '--', target],
    { cwd: CHECKOUT_ROOT, timeout: 30_000, maxBuffer: 10 * 1024 * 1024 },
    (err, stdout, stderr) => {
      // eslint exits non-zero when it finds lint problems — that's a
      // successful run, not a server error. Only a missing binary or a
      // timeout is a real failure.
      if (err && err.code === undefined) {
        return res.status(500).json({ error: 'Failed to run eslint.' });
      }
      res.type('text/plain').send(stdout + (stderr || ''));
    }
  );
});

module.exports = router;
```

