Here's a function that builds the query dynamically from whatever filters are present, using parameterized values so you're safe from SQL injection:

```typescript
import { Pool } from 'pg';

const pool = new Pool();

interface CustomerFilters {
  status?: string;
  city?: string;
  signupYear?: number;
}

interface Customer {
  id: number;
  name: string;
  email: string;
  status: string;
  city: string;
  signup_year: number;
}

export async function findCustomers(
  filters: CustomerFilters
): Promise<Customer[]> {
  const conditions: string[] = [];
  const values: unknown[] = [];

  // Whitelist the columns we allow filtering on. This maps the
  // filter keys to real column names, so nothing from the input
  // object ever reaches the SQL text directly.
  const filterColumns: Record<keyof CustomerFilters, string> = {
    status: 'status',
    city: 'city',
    signupYear: 'signup_year',
  };

  for (const key of Object.keys(filterColumns) as (keyof CustomerFilters)[]) {
    const value = filters[key];
    if (value !== undefined) {
      values.push(value);
      conditions.push(`${filterColumns[key]} = $${values.length}`);
    }
  }

  const whereClause =
    conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';

  const query = `
    SELECT id, name, email, status, city, signup_year
    FROM customers
    ${whereClause}
    ORDER BY name
  `;

  const result = await pool.query<Customer>(query, values);
  return result.rows;
}
```

