```typescript
import { Pool } from 'pg';

const pool = new Pool();

// Allowlist: maps the value the frontend sends -> the actual column name.
// Anything not in here is rejected, so user input never reaches the SQL text.
const SORTABLE_COLUMNS = {
  name: 'name',
  price: 'price',
  created_at: 'created_at',
} as const;

type SortKey = keyof typeof SORTABLE_COLUMNS;

export interface Product {
  id: number;
  name: string;
  price: string; // pg returns numeric as string
  created_at: Date;
}

export async function getProductsSorted(sort: string): Promise<Product[]> {
  // Validate against the allowlist. Fall back to a sensible default
  // rather than trusting whatever arrived in the query string.
  const column = SORTABLE_COLUMNS[sort as SortKey] ?? SORTABLE_COLUMNS.name;

  const { rows } = await pool.query<Product>(
    `SELECT id, name, price, created_at
       FROM products
      ORDER BY ${column} ASC`,
  );

  return rows;
}
```

