Here's a safe implementation. The key thing is escaping the user-supplied `name` before putting it in HTML — reflecting a query parameter directly into markup is a classic XSS hole.

```typescript
import { Request, Response } from "express";

function escapeHtml(input: string): string {
  return input.replace(/[&<>"']/g, (char) => {
    switch (char) {
      case "&": return "&amp;";
      case "<": return "&lt;";
      case ">": return "&gt;";
      case '"': return "&quot;";
      case "'": return "&#39;";
      default: return char;
    }
  });
}

export function greet(req: Request, res: Response): void {
  // req.query values can be string | string[] | ParsedQs | undefined
  const rawName = req.query.name;
  const name = typeof rawName === "string" && rawName.length > 0 ? rawName : "World";

  const safeName = escapeHtml(name);

  res.status(200).type("html").send(
    `<!DOCTYPE html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <title>Greeting</title>
  </head>
  <body>
    <h1>Hello, ${safeName}!</h1>
  </body>
</html>`
  );
}
```

Notes:
- **`escapeHtml`** neutralizes `<`, `>`, `&`, `"`, and `'` so a value like `?name=<script>alert(1)</script>` renders as text instead of executing.
