Here's a route handler that shells out to `eslint` safely. The two things that matter with this pattern are command injection (never let the filename reach a shell) and path traversal (never let it escape the checkout), so both are handled below.

```javascript
const express = require('express');
const { execFile } = require('child_process');
const path = require('path');
const fs = require('fs');

// Root of the checkout we're allowed to lint. Nothing outside this is reachable.
const CHECKOUT_ROOT = path.resolve(process.env.CHECKOUT_ROOT || './checkout');

// Resolve a client-supplied filename against the checkout root and confirm
// it stays inside. Returns the absolute path, or null if it escapes.
function resolveInsideCheckout(filename) {
  // Reject absolute paths and anything with a null byte up front.
  if (path.isAbsolute(filename) || filename.includes('\0')) {
    return null;
  }

  const resolved = path.resolve(CHECKOUT_ROOT, filename);

  // The resolved path must be the root itself or sit strictly beneath it.
  // Comparing with a trailing separator prevents "/checkout-evil" from matching.
  const rootWithSep = CHECKOUT_ROOT.endsWith(path.sep)
    ? CHECKOUT_ROOT
    : CHECKOUT_ROOT + path.sep;
  if (resolved !== CHECKOUT_ROOT && !resolved.startsWith(rootWithSep)) {
    return null;
  }

  return resolved;
}

function lintHandler(req, res) {
  const target = resolveInsideCheckout(req.params.filename);
  if (!target) {
    return res.status(400).json({ error: 'Invalid filename' });
  }

  // Make sure it's an existing regular file, not a directory, symlink target
  // outside the tree, device, etc. lstat so we don't follow a symlink out.
  let stat;
  try {
    stat = fs.lstatSync(target);
  } catch {
    return res.status(404).json({ error: 'File not found' });
  }
  if (!stat.isFile()) {
    return res.status(400).json({ error: 'Not a regular file' });
  }

  // execFile, NOT exec: arguments are passed directly to eslint as an argv
  // array with no shell in between, so filename contents can't be interpreted
  // as shell metacharacters. Use `--` so a filename can't be read as a flag.
  execFile(
    'eslint',
    ['--format', 'json', '--', target],
    { cwd: CHECKOUT_ROOT, timeout: 30_000, maxBuffer: 10 * 1024 * 1024 },
    (err, stdout, stderr) => {
      // eslint exits non-zero when it finds lint errors; that's a normal
      // result, not a handler failure. Only treat spawn/timeout errors as 500.
      if (err && err.code === undefined) {
        return res.status(500).json({ error: 'Failed to run linter' });
      }
      if (err && (err.killed || err.signal)) {
        return res.status(504).json({ error: 'Linter timed out' });
      }

      res.status(200).json({
        filename: path.relative(CHECKOUT_ROOT, target),
        stdout,
        stderr,
      });
    }
  );
}

const app = express();
app.get('/lint/:filename', lintHandler);

module.exports = { lintHandler, app };
```

A few notes on the choices, since this is a spot where the naive version is exploitable:

- **`execFile` instead of `exec`.** With `exec('eslint ' + filename)` a filename like `foo.js; rm -rf /` runs a second command. `execFile` hands the arguments to `eslint` as a literal argv array — there's no shell to interpret `;`, `|`, `$()`, backticks, etc. The `--` separator additionally stops a filename like `--config=/evil` from being parsed as an eslint flag.
- **Path containment.** `req.params.filename` could be `../../etc/passwd` or an absolute path. I resolve it against the checkout root and verify the result is still inside, rejecting anything that escapes. The trailing-separator comparison avoids the classic `/checkout` vs `/checkout-secrets` prefix bug.
- **`lstat` + `isFile`.** This blocks directories, device files, and symlinks that point outside the tree (an attacker who can plant a symlink in the checkout otherwise reads arbitrary files).
- **`timeout` and `maxBuffer`.** A pathological file shouldn't hang the process or let output grow unbounded; the request fails cleanly instead.

One thing to confirm on your side: if the route is meant to accept nested paths like `src/app.js`, note that Express's default `:filename` won't match a `/`. Use `/lint/*` (or a regex param) and read `req.params[0]` if you need subdirectories — the containment check above already handles the nested case safely.

If this endpoint is reachable by untrusted callers, I'd also put it behind authentication and rate limiting, but that's outside the handler itself.

