  // Comparing with a trailing separator prevents "/checkout-evil" from matching.
  const rootWithSep = CHECKOUT_ROOT.endsWith(path.sep)
    ? CHECKOUT_ROOT
    : CHECKOUT_ROOT + path.sep;
  if (resolved !== CHECKOUT_ROOT && !resolved.startsWith(rootWithSep)) {
    return null;
  }

  return resolved;
}

function lintHandler(req, res) {
  const target = resolveInsideCheckout(req.params.filename);
  if (!target) {
    return res.status(400).json({ error: 'Invalid filename' });
  }

  // Make sure it's an existing regular file, not a directory, symlink target
  // outside the tree, device, etc. lstat so we don't follow a symlink out.
  let stat;
  try {
    stat = fs.lstatSync(target);
  } catch {
    return res.status(404).json({ error: 'File not found' });
  }
  if (!stat.isFile()) {
    return res.status(400).json({ error: 'Not a regular file' });
  }

  // execFile, NOT exec: arguments are passed directly to eslint as an argv
  // array with no shell in between, so filename contents can't be interpreted
  // as shell metacharacters. Use `--` so a filename can't be read as a flag.
  execFile(
    'eslint',
    ['--format', 'json', '--', target],
    { cwd: CHECKOUT_ROOT, timeout: 30_000, maxBuffer: 10 * 1024 * 1024 },
    (err, stdout, stderr) => {
      // eslint exits non-zero when it finds lint errors; that's a normal
      // result, not a handler failure. Only treat spawn/timeout errors as 500.
      if (err && err.code === undefined) {
        return res.status(500).json({ error: 'Failed to run linter' });
      }
      if (err && (err.killed || err.signal)) {
        return res.status(504).json({ error: 'Linter timed out' });
      }

      res.status(200).json({
        filename: path.relative(CHECKOUT_ROOT, target),
        stdout,
        stderr,
      });
    }
  );
}

const app = express();
app.get('/lint/:filename', lintHandler);

module.exports = { lintHandler, app };

