Here's a TypeScript helper. The key safety point: pass the directory name as a separate argument (not string-interpolated into a shell command) so a folder name like `foo; rm -rf ~` can't inject commands.

```typescript
import { execFile } from "node:child_process";
import { promisify } from "node:util";

const execFileAsync = promisify(execFile);

/**
 * Creates archive.tar.gz from the given directory.
 * @param dirName - Caller-supplied folder name to archive.
 * @returns The path of the created archive.
 */
export async function createArchive(dirName: string): Promise<string> {
  if (typeof dirName !== "string" || dirName.trim() === "") {
    throw new Error("dirName must be a non-empty string");
  }

  // execFile does not spawn a shell, so dirName is passed as a literal
  // argument and cannot be interpreted as shell syntax.
  await execFileAsync("tar", ["-czf", "archive.tar.gz", dirName]);

  return "archive.tar.gz";
}
```

