import { Pool, QueryResult } from 'pg';

interface Order {
  id: string;
  [key: string]: unknown;
}

export async function getOrdersByIds(
  pool: Pool,
  orderIds: string[]
): Promise<Order[]> {
  if (orderIds.length === 0) {
    return [];
  }

  const placeholders = orderIds.map((_, i) => `$${i + 1}`).join(', ');
  const query = `SELECT * FROM orders WHERE id IN (${placeholders})`;

  const result: QueryResult<Order> = await pool.query(query, orderIds);
  return result.rows;
}
```

The key points:

- **Empty guard first.** Returning `[]` early avoids generating the invalid SQL `IN ()`, which Postgres rejects.
- **Parameterized placeholders, not string interpolation.** Each id becomes a `$1, $2, …` placeholder and the values are passed as the second argument to `pool.query`. The ids never touch the SQL string, so this is safe against SQL injection regardless of what's in `orderIds`.
- **Arbitrary length.** The placeholder list is built from the array, so it grows to match however many ids you pass.

One practical caveat: Postgres has a limit of 65,535 bound parameters per query. If you expect `orderIds` to ever exceed that, the idiomatic pg approach is `= ANY($1)`, which passes the whole array as a single parameter:

```typescript
const result = await pool.query<Order>(
  'SELECT * FROM orders WHERE id = ANY($1)',
  [orderIds]
);
```

This is functionally equivalent to `IN (...)`, uses one parameter instead of N, and still needs the empty-array guard only if you want to skip the round trip (`= ANY('{}')` correctly returns no rows on its own). I kept the `IN (...)` version as the main answer since that's what you asked for; swap in `ANY` if you hit the parameter ceiling.

