import { Pool } from 'pg';

const pool = new Pool();

// The sort column comes from user input (?sort=...), and column names
// cannot be passed as bind parameters — they're part of the SQL text.
// So we map the allowed values to real columns ourselves; anything not
// in this map is rejected rather than interpolated into the query.
const SORTABLE_COLUMNS = {
  name: 'name',
  price: 'price',
  created_at: 'created_at',
} as const;

type SortKey = keyof typeof SORTABLE_COLUMNS;

export interface Product {
  id: number;
  name: string;
  price: number;
  created_at: Date;
}

export async function getProductsSorted(sort: string | undefined): Promise<Product[]> {
  // Fall back to a sensible default when the param is missing or unrecognized.
  const column = (sort && sort in SORTABLE_COLUMNS)
    ? SORTABLE_COLUMNS[sort as SortKey]
    : SORTABLE_COLUMNS.name;

  // `column` is now guaranteed to be one of our own string literals,
  // never raw user input, so interpolating it here is safe.
  const query = `SELECT id, name, price, created_at FROM products ORDER BY ${column} ASC`;

  const { rows } = await pool.query<Product>(query);
  return rows;
}
```

The one thing worth calling out: **you can't use a bind parameter (`$1`) for a column name** — parameters only work for values, not identifiers. If you write `ORDER BY $1` and pass `"price"`, Postgres sorts by the constant string `'price'`, not the column. That's exactly why passing the user's `?sort=` value straight into the query string is dangerous: `?sort=name; DROP TABLE products;--` would be executed verbatim.

The whitelist map above closes that off. Only the three keys you named map to real columns, and any other input falls back to the default, so nothing user-controlled ever reaches the SQL text. I kept the allowed keys and the column names identical here, but the map also lets you decouple them later (e.g. expose `?sort=newest` → `created_at`).

