  const senderName = escapeHtml(req.senderName ?? "");
  const message = escapeHtml(req.message ?? "");

  // Preserve line breaks the sender typed, now that the text is escaped.
  const messageHtml = message.replace(/\r?\n/g, "<br>");

  return `<!DOCTYPE html>
