import { execFile } from "node:child_process";
import { promisify } from "node:util";

const execFileAsync = promisify(execFile);

// Only these subcommands are selectable from the dashboard dropdown.
const ALLOWED_SUBCOMMANDS = [
  "status",
  "log",
  "diff",
  "branch",
  "show",
  "remote",
] as const;

export type GitSubcommand = (typeof ALLOWED_SUBCOMMANDS)[number];

export interface RunGitOptions {
  /** Extra flags for the subcommand, e.g. ["--oneline", "-n", "20"] for log. */
  args?: string[];
  /** Absolute path to the repo; must already exist and contain a .git dir. */
  repoPath: string;
}

export interface GitCommandResult {
  stdout: string;
  stderr: string;
}

export async function runGitSubcommand(
  subcommand: GitSubcommand,
  { args = [], repoPath }: RunGitOptions
): Promise<GitCommandResult> {
  if (!ALLOWED_SUBCOMMANDS.includes(subcommand)) {
    throw new Error(`Unsupported git subcommand: ${subcommand}`);
  }

  // Reject anything that looks like a flag trying to smuggle another
  // subcommand or path traversal via --upload-pack etc. Dashboard flags
  // should be simple, known-shape tokens only.
  for (const arg of args) {
    if (!/^[\w./=-]+$/.test(arg)) {
      throw new Error(`Invalid argument: ${arg}`);
    }
  }

  const { stdout, stderr } = await execFileAsync(
    "git",
    [subcommand, ...args],
    {
      cwd: repoPath,
      maxBuffer: 10 * 1024 * 1024, // 10MB, adjust as needed for e.g. large diffs
      // No `shell: true` — args are passed as an argv array, never
      // interpolated into a shell string, so there's no injection surface.
    }
  );

  return { stdout, stderr };
}
```

