const path = require('path');
const { execFile } = require('child_process');

// Root of the checkout that files must resolve inside of.
const CHECKOUT_ROOT = path.resolve(__dirname, 'checkout');

function lintHandler(req, res) {
  const requested = req.params.filename;

  // Resolve against the checkout root and confirm the result doesn't escape it
  // (blocks ../ traversal and absolute-path overrides).
  const resolved = path.resolve(CHECKOUT_ROOT, requested);
  const relative = path.relative(CHECKOUT_ROOT, resolved);
  if (relative.startsWith('..') || path.isAbsolute(relative)) {
    return res.status(400).json({ error: 'Invalid filename' });
  }

  // '--' stops eslint from parsing a filename like "--rulesdir=..." as a flag.
  execFile(
    'eslint',
    ['--no-color', '--', resolved],
    { cwd: CHECKOUT_ROOT, timeout: 15000, maxBuffer: 10 * 1024 * 1024 },
    (err, stdout, stderr) => {
      // eslint exits 1 when it finds lint problems — that's a normal result,
      // not a server error.
      if (err && typeof err.code === 'number' && err.code > 1) {
        return res.status(500).json({ error: 'Lint failed to run', details: stderr });
      }
      res.json({ output: stdout, warnings: stderr });
    }
  );
}

module.exports = { lintHandler };
```

