Here's a handler using ESLint's Node API (avoids shell injection entirely) with path validation to keep the lint target inside your checkout directory:

```javascript
const path = require('path');
const { ESLint } = require('eslint');

const CHECKOUT_ROOT = path.resolve(process.env.CHECKOUT_ROOT || '/path/to/checkout');

async function lintFileHandler(req, res) {
  const requested = req.params.filename;

  if (typeof requested !== 'string' || requested.length === 0) {
    return res.status(400).json({ error: 'filename is required' });
  }

  // Resolve against the checkout root and make sure we didn't escape it
  // (blocks "../../etc/passwd", absolute paths, symlink tricks via realpath, etc.)
  const resolved = path.resolve(CHECKOUT_ROOT, requested);
  const relative = path.relative(CHECKOUT_ROOT, resolved);
  if (relative.startsWith('..') || path.isAbsolute(relative)) {
    return res.status(400).json({ error: 'invalid filename' });
  }

  let realResolved;
  try {
    realResolved = await fs.promises.realpath(resolved);
  } catch {
    return res.status(404).json({ error: 'file not found' });
  }
  const realRoot = await fs.promises.realpath(CHECKOUT_ROOT);
  if (!realResolved.startsWith(realRoot + path.sep)) {
    return res.status(400).json({ error: 'invalid filename' });
  }

  try {
    const eslint = new ESLint({ cwd: CHECKOUT_ROOT });
    const results = await eslint.lintFiles([realResolved]);
    const formatter = await eslint.loadFormatter('stylish');
    const output = formatter.format(results);

    return res.json({
      output,
      errorCount: results.reduce((n, r) => n + r.errorCount, 0),
      warningCount: results.reduce((n, r) => n + r.warningCount, 0),
    });
  } catch (err) {
    return res.status(500).json({ error: 'lint failed', detail: err.message });
  }
}

module.exports = { lintFileHandler };
```

Also add `const fs = require('fs');` at the top.

Why it's built this way, since the filename is attacker-controllable:

- **No shell involved** — the ESLint API is called in-process, so there's no `exec('eslint ' + filename)` string to inject into. If you'd rather shell out to the CLI, use `execFile('eslint', [realResolved])` (array args, no `shell: true`) — never string-concatenate into a shell command.
- **Path traversal check** — `path.resolve` + `path.relative` rejects `../../etc/passwd` style payloads before touching the filesystem.
- **`realpath` check** — catches symlinks inside the checkout that point outside it, which the string-based check alone wouldn't catch.

