 * (no path separators) and must resolve inside `uploadsDir`.
 */
export async function resizeImage(
  uploadsDir: string,
  inputFilename: string
): Promise<string> {
  const resolvedUploadsDir = path.resolve(uploadsDir);
  const inputPath = path.resolve(resolvedUploadsDir, inputFilename);

  if (path.dirname(inputPath) !== resolvedUploadsDir) {
    throw new Error("Invalid filename");
