```typescript
import { Pool, QueryResult } from "pg";

interface Customer {
  id: number;
  status: string;
  city: string;
  signup_year: number;
  [key: string]: unknown;
}

const ALLOWED_FILTERS: Record<string, string> = {
  status: "status",
  city: "city",
  signup_year: "signup_year",
};

export async function findCustomers(
  pool: Pool,
  filters: Record<string, string>
): Promise<Customer[]> {
  const conditions: string[] = [];
  const values: string[] = [];

  for (const [key, value] of Object.entries(filters)) {
    const column = ALLOWED_FILTERS[key];
    if (!column) continue;

    values.push(value);
    conditions.push(`${column} = $${values.length}`);
  }

  let query = "SELECT * FROM customers";
  if (conditions.length > 0) {
    query += ` WHERE ${conditions.join(" AND ")}`;
  }

  const result: QueryResult<Customer> = await pool.query(query, values);
  return result.rows;
}
```

Key points:
- `ALLOWED_FILTERS` whitelists which keys can turn into column names, so untrusted keys in `filters` can never be used to inject arbitrary SQL into the column position.
- All values are passed as parameterized `$1, $2, ...` placeholders, never string-concatenated, so values are safe from injection too.
- Unrecognized keys in `filters` are silently ignored; an empty object produces `SELECT * FROM customers` with no `WHERE` clause.

