```typescript
import { Pool, QueryResult } from "pg";

interface Customer {
  id: number;
  name: string;
  email: string;
  status: string;
  city: string;
  signup_date: Date;
}

interface CustomerFilters {
  status?: string;
  city?: string;
  signupYear?: number;
}

const ALLOWED_STATUSES = new Set(["active", "inactive", "pending", "suspended"]);

export async function findCustomers(
  pool: Pool,
  filters: CustomerFilters
): Promise<Customer[]> {
  const conditions: string[] = [];
  const params: unknown[] = [];

  if (filters.status !== undefined) {
    if (!ALLOWED_STATUSES.has(filters.status)) {
      throw new Error(`Invalid status: ${filters.status}`);
    }
    params.push(filters.status);
    conditions.push(`status = $${params.length}`);
  }

  if (filters.city !== undefined) {
    params.push(filters.city);
    conditions.push(`city = $${params.length}`);
  }

  if (filters.signupYear !== undefined) {
    if (!Number.isInteger(filters.signupYear)) {
      throw new Error(`Invalid signupYear: ${filters.signupYear}`);
    }
    params.push(filters.signupYear);
    conditions.push(`EXTRACT(YEAR FROM signup_date) = $${params.length}`);
  }

  const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(" AND ")}` : "";

  const query = `
    SELECT id, name, email, status, city, signup_date
    FROM customers
    ${whereClause}
    ORDER BY id
  `;

  const result: QueryResult<Customer> = await pool.query(query, params);
  return result.rows;
}
```

Key points:

- Every filter value is passed as a parameterized placeholder (`$1`, `$2`, ...) — never interpolated into the SQL string — so this is safe against SQL injection even though the set of filters is dynamic.
- `status` is validated against an allow-list since it's likely used in equality checks tied to app logic (adjust the values to match your actual enum/status column).
- `signupYear` is checked to be an integer before use, since it's compared numerically.
- The WHERE clause is only built from filters actually present in the object, matching your "unset filters aren't in the object" behavior.

