```typescript
import { Pool, RowDataPacket } from 'mysql2/promise';

export interface Product extends RowDataPacket {
  id: number;
  name: string;
  price: number;
  // ...other columns as needed
}

function escapeLikePattern(input: string): string {
  // Escape LIKE wildcards so a literal '%' or '_' in the search text
  // doesn't get treated as a pattern match.
  return input.replace(/[\\%_]/g, (char) => `\\${char}`);
}

export async function searchProductsByName(
  pool: Pool,
  searchText: string
): Promise<Product[]> {
  const pattern = `%${escapeLikePattern(searchText)}%`;

  const [rows] = await pool.query<Product[]>(
    'SELECT * FROM products WHERE name LIKE ? ESCAPE \'\\\\\'',
    [pattern]
  );

  return rows;
}
```

Key points:
- Uses `?` placeholders so mysql2 parameterizes the query — no string concatenation, no SQL injection risk.
- Escapes `%`, `_`, and `\` in the user's input before wrapping it in wildcards, with an explicit `ESCAPE '\\'` clause, so someone searching for `50%_off` matches that literal text instead of it being interpreted as a pattern.
- Takes `pool` as a parameter rather than importing a global connection — adjust to match how you manage your DB connection elsewhere in the codebase.

