const ALLOWED_SUBCOMMANDS = [
  'status',
  'log',
  'diff',
  'branch',
  'show',
  'blame',
  'reflog',
] as const;

type GitSubcommand = typeof ALLOWED_SUBCOMMANDS[number];

interface GitResult {
  stdout: string;
  stderr: string;
  exitCode: number;
}

export async function runGitCommand(
  subcommand: string,
  repoPath: string,
  args: string[] = []
): Promise<GitResult> {
  // Validate subcommand against whitelist
  if (!ALLOWED_SUBCOMMANDS.includes(subcommand as GitSubcommand)) {
    throw new Error(`Subcommand '${subcommand}' is not allowed`);
  }

  try {
    const { stdout, stderr } = await execFileAsync(
      'git',
      [subcommand, ...args],
      {
        cwd: repoPath,
        maxBuffer: 10 * 1024 * 1024, // 10MB buffer for large outputs
      }
    );

    return {
      stdout,
      stderr,
      exitCode: 0,
    };
  } catch (error: any) {
    // execFile throws on non-zero exit codes
    return {
      stdout: error.stdout || '',
      stderr: error.stderr || '',
      exitCode: error.code || 1,
    };
  }
}
```

