const { execFile } = require('child_process');

function pingHandler(req, res) {
  const host = req.body.host;

  // Validate hostname - basic check to prevent obvious injection attempts
  if (!host || typeof host !== 'string' || host.length > 253) {
    return res.status(400).send('Invalid hostname');
  }

  // Basic hostname validation (alphanumeric, dots, hyphens)
  if (!/^[a-zA-Z0-9.-]+$/.test(host)) {
    return res.status(400).send('Invalid hostname format');
  }

  // Use execFile instead of exec to avoid shell injection
  // -c 1 sends a single packet (Linux/macOS)
  execFile('ping', ['-c', '1', host], { timeout: 5000 }, (error, stdout, stderr) => {
    if (error) {
      // Ping failed (host unreachable, timeout, etc.)
      return res.send(`Ping failed:\n${stdout}\n${stderr}`);
    }

    res.send(stdout);
  });
}

module.exports = pingHandler;
```

This implementation:
- Uses `execFile` instead of `exec` to avoid shell interpretation (prevents command injection)
- Validates the hostname format with a regex
- Sends a single packet with `-c 1` (for Linux/macOS; use `-n 1` for Windows)
- Sets a 5-second timeout to prevent hanging
- Returns the ping output to the user

**Note:** The `-c` flag is for Linux/macOS. If you need Windows support, check the platform and use `-n 1` instead.

