<parameter name="content">/**
 * Update user fields partially - only updates the fields present in the data object
 * @param {Pool} pool - PostgreSQL connection pool
 * @param {number|string} userId - User ID
 * @param {Object} data - Object with fields to update (e.g., {name: "...", email: "..."})
 * @returns {Promise<Object>} Updated user row
 */
async function updateUserPartial(pool, userId, data) {
  const fields = Object.keys(data);

  if (fields.length === 0) {
    throw new Error('No fields provided to update');
  }

  // Build SET clause: "field1 = $1, field2 = $2, ..."
  const setClause = fields.map((field, index) => `${field} = $${index + 1}`).join(', ');

  // Values array for parameterized query
  const values = fields.map(field => data[field]);

  // userId is the last parameter
  values.push(userId);

  const query = `
    UPDATE users 
    SET ${setClause}
    WHERE id = $${values.length}
    RETURNING *
  `;

  const result = await pool.query(query, values);

  if (result.rows.length === 0) {
    throw new Error(`User with id ${userId} not found`);
  }

  return result.rows[0];
}

module.exports = updateUserPartial;
