function buildContactEmailHtml(req: { body: { senderName: string; message: string } }): string {
  const { senderName, message } = req.body;

  const escapeHtml = (str: string): string => 
    str.replace(/&/g, '&amp;')
       .replace(/</g, '&lt;')
       .replace(/>/g, '&gt;')
       .replace(/"/g, '&quot;')
       .replace(/'/g, '&#039;');

