```typescript
import { execSync } from 'child_process';

export function runGitCommand(subcommand: string): string {
  // Validate that subcommand is a known git subcommand to prevent injection
  const allowedCommands = ['status', 'log', 'diff', 'branch', 'show', 'remote', 'tag', 'stash'];

  if (!allowedCommands.includes(subcommand)) {
    throw new Error(`Unknown git subcommand: ${subcommand}`);
  }

  try {
    const output = execSync(`git ${subcommand}`, { 
      encoding: 'utf-8',
      stdio: ['pipe', 'pipe', 'pipe'] // capture stderr to prevent console spam
    });
    return output;
  } catch (error) {
    if (error instanceof Error) {
      throw new Error(`Git command failed: ${error.message}`);
    }
    throw error;
  }
}
```

