I'll write a TypeScript helper that reads the query parameter and displays it in a status banner:

```typescript
function showStatusMessage(bannerSelector: string = '.status-banner'): void {
  const params = new URLSearchParams(window.location.search);
  const message = params.get('msg');

  if (!message) return;

  const banner = document.querySelector(bannerSelector);
  if (!banner) return;

  banner.textContent = decodeURIComponent(message);
  banner.classList.add('show');

  // Clean up the URL
  window.history.replaceState(null, '', window.location.pathname);
}

// Call on page load
document.addEventListener('DOMContentLoaded', () => {
  showStatusMessage();
});
```

